import { VoterCardData } from "./types";
import { CANVAS_WIDTH, CANVAS_HEIGHT, POTATO_IMAGES } from "./constants";

/**
 * Loads an image with a fallback handler.
 * Returns true if loaded successfully, false otherwise.
 */
function loadImageWithFallback(
  img: HTMLImageElement,
  timeout: number = 5000
): Promise<boolean> {
  return new Promise((resolve) => {
    let loaded = false;

    const timeoutId = setTimeout(() => {
      if (!loaded) {
        resolve(false);
      }
    }, timeout);

    img.onload = () => {
      loaded = true;
      clearTimeout(timeoutId);
      resolve(true);
    };

    img.onerror = () => {
      loaded = true;
      clearTimeout(timeoutId);
      resolve(false);
    };

    // Trigger the load
    if (img.src) {
      if (img.complete) {
        loaded = true;
        clearTimeout(timeoutId);
        resolve(true);
      }
    }
  });
}

/**
 * The core drawing engine with modern, minimal ballot card design.
 * Optimized for Instagram readability with larger fonts.
 * @param canvas - The HTML5 Canvas reference
 * @param data - The state containing names, titles, and votes
 * @throws Error with user-friendly message if canvas doesn't support 2D context
 */
export async function drawCard(
  canvas: HTMLCanvasElement,
  data: VoterCardData
): Promise<void> {
  try {
    const ctx = canvas.getContext("2d");

    // Check if canvas context is available
    if (!ctx) {
      throw new Error(
        "Your browser doesn't support canvas rendering. Please use a modern browser like Chrome, Firefox, Safari, or Edge."
      );
    }

    // 1. Clear and Set Dimensions
    canvas.width = CANVAS_WIDTH;
    canvas.height = CANVAS_HEIGHT;

    // 2. White Card Background
    ctx.fillStyle = "#FFFFFF";
    ctx.fillRect(0, 0, CANVAS_WIDTH, CANVAS_HEIGHT);

    // 3. Load Potato Asset as Watermark
    const potatoImg = new Image();
    const arrayIndex = Math.max(
      0,
      Math.min(data.potatoIndex - 1, POTATO_IMAGES.length - 1)
    );
    potatoImg.src = POTATO_IMAGES[arrayIndex];

    const imageLoaded = await loadImageWithFallback(potatoImg);

    // Draw Potato Watermark (semi-transparent, centered)
    if (imageLoaded) {
      const potatoSize = 500;
      const potatoX = CANVAS_WIDTH / 2 - potatoSize / 2;
      const potatoY = CANVAS_HEIGHT / 2 - potatoSize / 2;

      ctx.globalAlpha = 0.06;
      ctx.drawImage(potatoImg, potatoX, potatoY, potatoSize, potatoSize);
      ctx.globalAlpha = 1.0;
    }

    // 4. Left Accent Bar
    ctx.fillStyle = "#7C3AED";
    ctx.fillRect(100, 160, 6, 120);

    // 5. "MY VOTER CARD" Label
    ctx.fillStyle = "#A1A1AA";
    ctx.font = "600 32px sans-serif";
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    ctx.fillText("MY VOTER CARD", 130, 200);

    // 6. Election Title
    ctx.fillStyle = "#18181B";
    ctx.font = "bold 68px sans-serif";
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    const title = data.electionTitle || "2024 Voter Guide";
    const displayTitle = title.length > 18 ? title.substring(0, 15) + "..." : title;
    ctx.fillText(displayTitle, 130, 260);

    // 7. Violet Divider Under Title
    ctx.strokeStyle = "#7C3AED";
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(130, 345);
    ctx.lineTo(CANVAS_WIDTH - 130, 345);
    ctx.stroke();

    // 8. Section Label
    let sectionLabelY = 400;
    const filledRows = data.rows.filter(
      (r) => r.position.trim() && r.decision.trim()
    );
    const candidates = filledRows.filter((r) => r.type === "candidate");
    const measures = filledRows.filter((r) => r.type === "measure");

    let sectionLabel = "";
    if (candidates.length > 0 && measures.length > 0) {
      sectionLabel = "MY BALLOT";
    } else if (candidates.length > 0) {
      sectionLabel = "CANDIDATES";
    } else if (measures.length > 0) {
      sectionLabel = "PROPOSITIONS";
    }

    if (sectionLabel) {
      ctx.fillStyle = "#A1A1AA";
      ctx.font = "600 34px sans-serif";
      ctx.textAlign = "left";
      ctx.textBaseline = "top";
      ctx.fillText(sectionLabel, 130, sectionLabelY);
    }

    // 9. Draw Voting Rows
    let currentY = sectionLabelY + 70;

    for (const row of filledRows) {
      // Position text (left-aligned)
      ctx.fillStyle = "#71717A";
      ctx.font = "400 44px sans-serif";
      ctx.textAlign = "left";
      ctx.textBaseline = "top";
      ctx.fillText(row.position, 130, currentY);

      // Decision text (right-aligned)
      ctx.fillStyle = "#18181B";
      ctx.font = "600 44px sans-serif";
      ctx.textAlign = "right";
      ctx.textBaseline = "top";
      ctx.fillText(row.decision, CANVAS_WIDTH - 130, currentY);

      currentY += 50;

      // Note (if present)
      if (row.note.trim()) {
        ctx.fillStyle = "#A1A1AA";
        ctx.font = "italic 400 32px sans-serif";
        ctx.textAlign = "left";
        ctx.textBaseline = "top";
        ctx.fillText(row.note, 130, currentY);
        currentY += 30;
      }

      // Divider line below row
      const dividerY = currentY + 15;
      ctx.strokeStyle = "#E4E4E7";
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(130, dividerY);
      ctx.lineTo(CANVAS_WIDTH - 130, dividerY);
      ctx.stroke();

      currentY = dividerY + 45;
    }

    // 10. Footer Area
    // Divider line
    ctx.strokeStyle = "#E4E4E7";
    ctx.lineWidth = 1;
    ctx.beginPath();
    ctx.moveTo(200, 1620);
    ctx.lineTo(CANVAS_WIDTH - 200, 1620);
    ctx.stroke();

    // "Prepared by" text
    ctx.fillStyle = "#A1A1AA";
    ctx.font = "400 32px sans-serif";
    ctx.textAlign = "center";
    ctx.textBaseline = "top";
    const preparedText = data.name
      ? `Prepared by ${data.name}`
      : "Prepared by Anonymous Potato";
    ctx.fillText(preparedText, CANVAS_WIDTH / 2, 1665);

    // 11. Branding Footer
    ctx.fillStyle = "#D4D4D8";
    ctx.font = "400 28px sans-serif";
    ctx.textAlign = "center";
    ctx.fillText("Made on www.potatovotes.com", CANVAS_WIDTH / 2, 1800);
  } catch (error) {
    // Re-throw with context for the component to handle
    if (error instanceof Error) {
      throw new Error(`Failed to generate card: ${error.message}`);
    }
    throw new Error("Failed to generate card: An unexpected error occurred");
  }
}
